fun solve(nums: Array<Long>): Array<Long> {
    val n = nums.size
    val ans = Array(2 * n) { 0L }

    // First n elements are the same as nums
    for (i in 0 until n) {
        ans[i] = nums[i]
    }

    // Last n elements are nums in reverse order
    // ans[i + n] = nums[n - 1 - i] for 0 <= i <= n - 1
    for (i in 0 until n) {
        ans[i + n] = nums[n - 1 - i]
    }

    return ans
}
